SET @col_exists = (SELECT COUNT(*) FROM INFORMATION_SCHEMA.COLUMNS
  WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = 'municipalities' AND COLUMN_NAME = 'population');
SET @ddl = IF(@col_exists = 0,
  'ALTER TABLE municipalities ADD COLUMN population INT UNSIGNED NULL',
  'SELECT 1');
PREPARE stmt FROM @ddl; EXECUTE stmt; DEALLOCATE PREPARE stmt;

SET @col_exists = (SELECT COUNT(*) FROM INFORMATION_SCHEMA.COLUMNS
  WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = 'municipalities' AND COLUMN_NAME = 'area_km2');
SET @ddl = IF(@col_exists = 0,
  'ALTER TABLE municipalities ADD COLUMN area_km2 DECIMAL(10,2) NULL',
  'SELECT 1');
PREPARE stmt FROM @ddl; EXECUTE stmt; DEALLOCATE PREPARE stmt;

SET @col_exists = (SELECT COUNT(*) FROM INFORMATION_SCHEMA.COLUMNS
  WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = 'municipalities' AND COLUMN_NAME = 'elevation_m');
SET @ddl = IF(@col_exists = 0,
  'ALTER TABLE municipalities ADD COLUMN elevation_m INT NULL',
  'SELECT 1');
PREPARE stmt FROM @ddl; EXECUTE stmt; DEALLOCATE PREPARE stmt;

SET @col_exists = (SELECT COUNT(*) FROM INFORMATION_SCHEMA.COLUMNS
  WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = 'municipalities' AND COLUMN_NAME = 'postal_code');
SET @ddl = IF(@col_exists = 0,
  'ALTER TABLE municipalities ADD COLUMN postal_code VARCHAR(10) NULL',
  'SELECT 1');
PREPARE stmt FROM @ddl; EXECUTE stmt; DEALLOCATE PREPARE stmt;

SET @col_exists = (SELECT COUNT(*) FROM INFORMATION_SCHEMA.COLUMNS
  WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = 'municipalities' AND COLUMN_NAME = 'district');
SET @ddl = IF(@col_exists = 0,
  'ALTER TABLE municipalities ADD COLUMN district VARCHAR(150) NULL',
  'SELECT 1');
PREPARE stmt FROM @ddl; EXECUTE stmt; DEALLOCATE PREPARE stmt;

